1	package crypto
2	
3	import (
4		"crypto/aes"
5		"crypto/cipher"
6		"crypto/rand"
7		"encoding/hex"
8		"errors"
9		"fmt"
10		"io"
11		"os"
12	)
13	
14	// Key reads the ENCRYPTION_KEY env var (64 hex chars = 32 bytes = AES-256).
15	func Key() ([]byte, error) {
16		hexKey := os.Getenv("ENCRYPTION_KEY")
17		if hexKey == "" {
18			return nil, errors.New("ENCRYPTION_KEY not set")
19		}
20		return hex.DecodeString(hexKey)
21	}
22	
23	// Encrypt encrypts plaintext using AES-256-GCM and returns hex-encoded ciphertext.
24	func Encrypt(key []byte, plaintext string) (string, error) {
25		block, err := aes.NewCipher(key)
26		if err != nil {
27			return "", fmt.Errorf("crypto: new cipher: %w", err)
28		}
29		gcm, err := cipher.NewGCM(block)
30		if err != nil {
31			return "", fmt.Errorf("crypto: new gcm: %w", err)
32		}
33		nonce := make([]byte, gcm.NonceSize())
34		if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
35			return "", err
36		}
37		ciphertext := gcm.Seal(nonce, nonce, []byte(plaintext), nil)
38		return hex.EncodeToString(ciphertext), nil
39	}
40	
41	// Decrypt decrypts hex-encoded AES-256-GCM ciphertext and returns plaintext.
42	func Decrypt(key []byte, hexCiphertext string) (string, error) {
43		ciphertext, err := hex.DecodeString(hexCiphertext)
44		if err != nil {
45			return "", fmt.Errorf("crypto: decode hex: %w", err)
46		}
47		block, err := aes.NewCipher(key)
48		if err != nil {
49			return "", fmt.Errorf("crypto: new cipher: %w", err)
50		}
51		gcm, err := cipher.NewGCM(block)
52		if err != nil {
53			return "", fmt.Errorf("crypto: new gcm: %w", err)
54		}
55		nonceSize := gcm.NonceSize()
56		if len(ciphertext) < nonceSize {
57			return "", errors.New("crypto: ciphertext too short")
58		}
59		nonce, ct := ciphertext[:nonceSize], ciphertext[nonceSize:]
60		plaintext, err := gcm.Open(nil, nonce, ct, nil)
61		if err != nil {
62			return "", fmt.Errorf("crypto: decrypt: %w", err)
63		}
64		return string(plaintext), nil
65	}
