19	// Valid severity values.
20	var validSeverities = map[string]bool{
21		"low":      true,
22		"medium":   true,
23		"high":     true,
24		"critical": true,
25	}
26	
27	// Supported metrics that the worker can evaluate.
28	var supportedMetrics = map[string]bool{
29		"unresolved_interests":      true,
30		"low_provider_utilization":  true,
31		"overdue_work_orders":       true,
32	}
33	
34	// Service manages alert rules, alerts, and assignments.
35	type Service struct {
36		db    *sql.DB
37		audit *audit.Service
38	}
39	
40	// NewService creates a new alerts service.
41	func NewService(db *sql.DB, audit *audit.Service) *Service {
42		return &Service{db: db, audit: audit}
43	}
44	
45	// AlertRule represents an alert rule configuration.
46	type AlertRule struct {
47		ID              string          `json:"id"`
48		Name            string          `json:"name"`
49		Condition       json.RawMessage `json:"condition"`
50		Severity        string          `json:"severity"`
51		QuietHoursStart *string         `json:"quiet_hours_start"`
52		QuietHoursEnd   *string         `json:"quiet_hours_end"`
53		Enabled         bool            `json:"enabled"`
54		CreatedAt       string          `json:"created_at"`
55		UpdatedAt       string          `json:"updated_at"`
56	}
57	
58	// Alert represents a triggered alert.
59	type Alert struct {
60		ID         string          `json:"id"`
61		RuleID     string          `json:"rule_id"`
62		Severity   string          `json:"severity"`
63		Status     string          `json:"status"`
64		Data       json.RawMessage `json:"data"`
65		CreatedAt  string          `json:"created_at"`
66		ResolvedAt *string         `json:"resolved_at"`
67	}
68	
69	// AlertWithRule includes the rule name for list views.
70	type AlertWithRule struct {
71		Alert
72		RuleName string `json:"rule_name"`
73	}
74	
75	// Assignment represents an alert-to-user assignment.
76	type Assignment struct {
77		ID             string  `json:"id"`
78		AlertID        string  `json:"alert_id"`
79		AssigneeID     string  `json:"assignee_id"`
80		AssignedAt     string  `json:"assigned_at"`
81		AcknowledgedAt *string `json:"acknowledged_at"`
82	}
