84	// HandleListRules handles GET /admin/alert-rules.
85	func (s *Service) HandleListRules(c echo.Context) error {
86		rows, err := s.db.QueryContext(c.Request().Context(),
87			`SELECT id, name, condition, severity, quiet_hours_start::text, quiet_hours_end::text, enabled, created_at::text, updated_at::text
88			 FROM alert_rules ORDER BY created_at DESC`)
89		if err != nil {
90			return fmt.Errorf("alerts: list rules: %w", err)
91		}
92		defer rows.Close()
93	
94		rules := []AlertRule{}
95		for rows.Next() {
96			var r AlertRule
97			if err := rows.Scan(&r.ID, &r.Name, &r.Condition, &r.Severity, &r.QuietHoursStart, &r.QuietHoursEnd, &r.Enabled, &r.CreatedAt, &r.UpdatedAt); err != nil {
98				return fmt.Errorf("alerts: scan rule: %w", err)
99			}
100			rules = append(rules, r)
101		}
102		if err := rows.Err(); err != nil {
103			return fmt.Errorf("alerts: rules rows: %w", err)
104		}
105	
106		return c.JSON(http.StatusOK, map[string]interface{}{"alert_rules": rules})
107	}
