109	// HandleCreateRule handles POST /admin/alert-rules.
110	func (s *Service) HandleCreateRule(c echo.Context) error {
111		ctx := c.Request().Context()
112		user := auth.UserFromContext(c)
113	
114		var req struct {
115			Name            string          `json:"name"`
116			Condition       json.RawMessage `json:"condition"`
117			Severity        string          `json:"severity"`
118			QuietHoursStart *string         `json:"quiet_hours_start"`
119			QuietHoursEnd   *string         `json:"quiet_hours_end"`
120			Enabled         *bool           `json:"enabled"`
121		}
122		if err := c.Bind(&req); err != nil {
123			return httpx.NewAPIError(http.StatusBadRequest, "bad_request", "Invalid request body.")
124		}
125	
126		// Validate
127		fieldErrors := map[string][]string{}
128		if req.Name == "" {
129			fieldErrors["name"] = []string{"Name is required."}
130		}
131		if !validSeverities[req.Severity] {
132			fieldErrors["severity"] = []string{"Severity must be one of: low, medium, high, critical."}
133		}
134		if len(req.Condition) == 0 || string(req.Condition) == "null" {
135			fieldErrors["condition"] = []string{"Condition is required."}
136		} else {
137			var cond struct{ Metric string `json:"metric"` }
138			if json.Unmarshal(req.Condition, &cond) == nil && cond.Metric != "" && !supportedMetrics[cond.Metric] {
139				fieldErrors["condition"] = []string{"Unsupported metric. Supported: unresolved_interests, low_provider_utilization, overdue_work_orders."}
140			}
141		}
142		if len(fieldErrors) > 0 {
143			return httpx.NewValidationError(fieldErrors)
144		}
145	
146		enabled := true
147		if req.Enabled != nil {
148			enabled = *req.Enabled
149		}
150	
151		var r AlertRule
152		err := s.db.QueryRowContext(ctx,
153			`INSERT INTO alert_rules (id, name, condition, severity, quiet_hours_start, quiet_hours_end, enabled, created_at, updated_at)
154			 VALUES ($1, $2, $3, $4, $5, $6, $7, NOW(), NOW())
155			 RETURNING id, name, condition, severity, quiet_hours_start::text, quiet_hours_end::text, enabled, created_at::text, updated_at::text`,
156			uuid.New().String(), req.Name, req.Condition, req.Severity, req.QuietHoursStart, req.QuietHoursEnd, enabled,
157		).Scan(&r.ID, &r.Name, &r.Condition, &r.Severity, &r.QuietHoursStart, &r.QuietHoursEnd, &r.Enabled, &r.CreatedAt, &r.UpdatedAt)
158		if err != nil {
159			return fmt.Errorf("alerts: create rule: %w", err)
160		}
161	
162		s.audit.Log(ctx, audit.Event{
163			EventType:    "alert_rule_created",
164			ActorID:      user.ID,
165			ResourceType: "alert_rule",
166			ResourceID:   r.ID,
167			Metadata:     map[string]interface{}{"name": r.Name, "severity": r.Severity},
168		})
169	
170		return c.JSON(http.StatusCreated, map[string]interface{}{"alert_rule": r})
171	}
