173	// HandleUpdateRule handles PATCH /admin/alert-rules/:ruleId.
174	func (s *Service) HandleUpdateRule(c echo.Context) error {
175		ctx := c.Request().Context()
176		user := auth.UserFromContext(c)
177		ruleID := c.Param("ruleId")
178	
179		// Check rule exists
180		var existing AlertRule
181		err := s.db.QueryRowContext(ctx,
182			`SELECT id, name, condition, severity, quiet_hours_start::text, quiet_hours_end::text, enabled, created_at::text, updated_at::text
183			 FROM alert_rules WHERE id = $1`, ruleID,
184		).Scan(&existing.ID, &existing.Name, &existing.Condition, &existing.Severity, &existing.QuietHoursStart, &existing.QuietHoursEnd, &existing.Enabled, &existing.CreatedAt, &existing.UpdatedAt)
185		if err == sql.ErrNoRows {
186			return httpx.NewNotFoundError("Alert rule not found.")
187		}
188		if err != nil {
189			return fmt.Errorf("alerts: get rule: %w", err)
190		}
191	
192		var req struct {
193			Name            *string          `json:"name"`
194			Condition       *json.RawMessage `json:"condition"`
195			Severity        *string          `json:"severity"`
196			QuietHoursStart *string          `json:"quiet_hours_start"`
197			QuietHoursEnd   *string          `json:"quiet_hours_end"`
198			Enabled         *bool            `json:"enabled"`
199		}
200		if err := c.Bind(&req); err != nil {
201			return httpx.NewAPIError(http.StatusBadRequest, "bad_request", "Invalid request body.")
202		}
203	
204		// Apply partial updates
205		name := existing.Name
206		if req.Name != nil {
207			name = *req.Name
208		}
209		condition := existing.Condition
210		if req.Condition != nil {
211			condition = *req.Condition
212			// Validate metric
213			var cond struct{ Metric string `json:"metric"` }
214			if json.Unmarshal(condition, &cond) == nil && cond.Metric != "" && !supportedMetrics[cond.Metric] {
215				return httpx.NewValidationError(map[string][]string{
216					"condition": {"Unsupported metric. Supported: unresolved_interests, low_provider_utilization, overdue_work_orders."},
217				})
218			}
219		}
220		severity := existing.Severity
221		if req.Severity != nil {
222			if !validSeverities[*req.Severity] {
223				return httpx.NewValidationError(map[string][]string{
224					"severity": {"Severity must be one of: low, medium, high, critical."},
225				})
226			}
227			severity = *req.Severity
228		}
229		enabled := existing.Enabled
230		if req.Enabled != nil {
231			enabled = *req.Enabled
232		}
233		quietStart := existing.QuietHoursStart
234		if req.QuietHoursStart != nil {
235			quietStart = req.QuietHoursStart
236		}
237		quietEnd := existing.QuietHoursEnd
238		if req.QuietHoursEnd != nil {
239			quietEnd = req.QuietHoursEnd
240		}
241	
242		var r AlertRule
243		err = s.db.QueryRowContext(ctx,
244			`UPDATE alert_rules SET name = $1, condition = $2, severity = $3, quiet_hours_start = $4, quiet_hours_end = $5, enabled = $6, updated_at = NOW()
245			 WHERE id = $7
246			 RETURNING id, name, condition, severity, quiet_hours_start::text, quiet_hours_end::text, enabled, created_at::text, updated_at::text`,
247			name, condition, severity, quietStart, quietEnd, enabled, ruleID,
248		).Scan(&r.ID, &r.Name, &r.Condition, &r.Severity, &r.QuietHoursStart, &r.QuietHoursEnd, &r.Enabled, &r.CreatedAt, &r.UpdatedAt)
249		if err != nil {
250			return fmt.Errorf("alerts: update rule: %w", err)
251		}
252	
253		s.audit.Log(ctx, audit.Event{
254			EventType:    "alert_rule_updated",
255			ActorID:      user.ID,
256			ResourceType: "alert_rule",
257			ResourceID:   r.ID,
258			Metadata:     map[string]interface{}{"name": r.Name},
259		})
260	
261		return c.JSON(http.StatusOK, map[string]interface{}{"alert_rule": r})
262	}
