291	// HandleGetAlert handles GET /admin/alerts/:alertId.
292	func (s *Service) HandleGetAlert(c echo.Context) error {
293		ctx := c.Request().Context()
294		alertID := c.Param("alertId")
295	
296		var a AlertWithRule
297		err := s.db.QueryRowContext(ctx,
298			`SELECT a.id, a.rule_id, a.severity, a.status, a.data, a.created_at::text, a.resolved_at::text, ar.name
299			 FROM alerts a
300			 JOIN alert_rules ar ON ar.id = a.rule_id
301			 WHERE a.id = $1`, alertID,
302		).Scan(&a.ID, &a.RuleID, &a.Severity, &a.Status, &a.Data, &a.CreatedAt, &a.ResolvedAt, &a.RuleName)
303		if err == sql.ErrNoRows {
304			return httpx.NewNotFoundError("Alert not found.")
305		}
306		if err != nil {
307			return fmt.Errorf("alerts: get alert: %w", err)
308		}
309	
310		// Fetch assignments
311		assignRows, err := s.db.QueryContext(ctx,
312			`SELECT id, alert_id, assignee_id, assigned_at::text, acknowledged_at::text
313			 FROM alert_assignments WHERE alert_id = $1`, alertID)
314		if err != nil {
315			return fmt.Errorf("alerts: list assignments: %w", err)
316		}
317		defer assignRows.Close()
318	
319		assignments := []Assignment{}
320		for assignRows.Next() {
321			var asgn Assignment
322			if err := assignRows.Scan(&asgn.ID, &asgn.AlertID, &asgn.AssigneeID, &asgn.AssignedAt, &asgn.AcknowledgedAt); err != nil {
323				return fmt.Errorf("alerts: scan assignment: %w", err)
324			}
325			assignments = append(assignments, asgn)
326		}
327		if err := assignRows.Err(); err != nil {
328			return fmt.Errorf("alerts: assignment rows: %w", err)
329		}
330	
331		return c.JSON(http.StatusOK, map[string]interface{}{
332			"alert":       a,
333			"assignments": assignments,
