387	// HandleAcknowledgeAlert handles POST /admin/alerts/:alertId/acknowledge.
388	func (s *Service) HandleAcknowledgeAlert(c echo.Context) error {
389		ctx := c.Request().Context()
390		user := auth.UserFromContext(c)
391		alertID := c.Param("alertId")
392	
393		result, err := s.db.ExecContext(ctx,
394			`UPDATE alert_assignments SET acknowledged_at = NOW()
395			 WHERE alert_id = $1 AND assignee_id = $2 AND acknowledged_at IS NULL`,
396			alertID, user.ID,
397		)
398		if err != nil {
399			return fmt.Errorf("alerts: acknowledge: %w", err)
400		}
401	
402		rowsAffected, _ := result.RowsAffected()
403		if rowsAffected == 0 {
404			return httpx.NewNotFoundError("No pending assignment found for this alert.")
405		}
406	
407		s.audit.Log(ctx, audit.Event{
408			EventType:    "alert_acknowledged",
409			ActorID:      user.ID,
410			ResourceType: "alert",
411			ResourceID:   alertID,
412		})
413	
414		return c.JSON(http.StatusOK, map[string]interface{}{"message": "Alert acknowledged."})
415	}
