417	// EvaluateRules checks all enabled alert rules and creates alerts as needed.
418	func (s *Service) EvaluateRules(ctx context.Context, now time.Time) error {
419		rows, err := s.db.QueryContext(ctx,
420			`SELECT id, name, condition, severity, quiet_hours_start::text, quiet_hours_end::text, enabled
421			 FROM alert_rules WHERE enabled = true`)
422		if err != nil {
423			return fmt.Errorf("alerts: query rules: %w", err)
424		}
425		defer rows.Close()
426	
427		type ruleRow struct {
428			id              string
429			name            string
430			condition       json.RawMessage
431			severity        string
432			quietHoursStart *string
433			quietHoursEnd   *string
434		}
435	
436		var rules []ruleRow
437		for rows.Next() {
438			var r ruleRow
439			var enabled bool
440			if err := rows.Scan(&r.id, &r.name, &r.condition, &r.severity, &r.quietHoursStart, &r.quietHoursEnd, &enabled); err != nil {
441				return fmt.Errorf("alerts: scan rule: %w", err)
442			}
443			rules = append(rules, r)
444		}
445		if err := rows.Err(); err != nil {
446			return fmt.Errorf("alerts: rules rows: %w", err)
447		}
448	
449		for _, rule := range rules {
450			// Check quiet hours
451			if rule.severity != "critical" && inQuietHours(rule.quietHoursStart, rule.quietHoursEnd, now) {
452				continue
453			}
454	
455			// Parse condition
456			var cond struct {
457				Metric    string `json:"metric"`
458				Threshold int    `json:"threshold"`
459			}
460			if err := json.Unmarshal(rule.condition, &cond); err != nil {
461				continue
462			}
463	
464			// Evaluate metric
465			var metricValue int
466			var evalErr error
467			switch cond.Metric {
468			case "unresolved_interests":
469				evalErr = s.db.QueryRowContext(ctx,
470					`SELECT COUNT(*) FROM interests WHERE status = 'submitted' AND created_at < NOW() - INTERVAL '3 days'`,
471				).Scan(&metricValue)
472			case "low_provider_utilization":
473				evalErr = s.db.QueryRowContext(ctx,
474					`SELECT COUNT(*) FROM provider_profiles pp
475					 WHERE NOT EXISTS (SELECT 1 FROM services s WHERE s.provider_id = pp.id AND s.status = 'active')`,
476				).Scan(&metricValue)
477			case "overdue_work_orders":
478				evalErr = s.db.QueryRowContext(ctx,
479					`SELECT COUNT(*) FROM work_orders
480					 WHERE status IN ('dispatched', 'acknowledged', 'in_progress')
481					 AND updated_at < NOW() - INTERVAL '24 hours'`,
482				).Scan(&metricValue)
483			default:
484				continue
485			}
486			if evalErr != nil {
487				continue
488			}
489	
490			if metricValue < cond.Threshold {
491				continue
492			}
493	
494			// Check for recent unresolved alert for this rule (last hour)
495			var recentCount int
496			s.db.QueryRowContext(ctx,
497				`SELECT COUNT(*) FROM alerts
498				 WHERE rule_id = $1 AND status != 'resolved' AND created_at > NOW() - INTERVAL '1 hour'`,
499				rule.id,
500			).Scan(&recentCount)
501			if recentCount > 0 {
502				continue
503			}
504	
505			// Create alert
506			data, _ := json.Marshal(map[string]interface{}{
507				"metric": cond.Metric,
508				"value":  metricValue,
509			})
510			_, err := s.db.ExecContext(ctx,
511				`INSERT INTO alerts (id, rule_id, severity, status, data, created_at)
512				 VALUES ($1, $2, $3, 'new', $4, NOW())`,
513				uuid.New().String(), rule.id, rule.severity, data,
514			)
515			if err != nil {
516				continue
517			}
518		}
519	
