523	// CheckSLADeadlines finds overdue work orders and creates critical alerts.
524	func (s *Service) CheckSLADeadlines(ctx context.Context, now time.Time) error {
525		rows, err := s.db.QueryContext(ctx,
526			`SELECT id FROM work_orders
527			 WHERE status IN ('dispatched', 'acknowledged', 'in_progress')
528			 AND updated_at < NOW() - INTERVAL '24 hours'`)
529		if err != nil {
530			return fmt.Errorf("alerts: sla check query: %w", err)
531		}
532		defer rows.Close()
533	
534		for rows.Next() {
535			var woID string
536			if err := rows.Scan(&woID); err != nil {
537				continue
538			}
539	
540			// Check for existing SLA alert for this work order in last hour
541			var recentCount int
542			s.db.QueryRowContext(ctx,
543				`SELECT COUNT(*) FROM alerts
544				 WHERE status != 'resolved' AND data->>'work_order_id' = $1 AND created_at > NOW() - INTERVAL '1 hour'`,
545				woID,
546			).Scan(&recentCount)
547			if recentCount > 0 {
548				continue
549			}
550	
551			// We need a rule_id for SLA alerts. Use a sentinel approach: find or create a system SLA rule.
552			var slaRuleID string
553			err := s.db.QueryRowContext(ctx,
554				`SELECT id FROM alert_rules WHERE name = '__sla_breach_system'`,
555			).Scan(&slaRuleID)
556			if err == sql.ErrNoRows {
557				slaRuleID = uuid.New().String()
558				cond, _ := json.Marshal(map[string]string{"metric": "sla_breach"})
559				_, err = s.db.ExecContext(ctx,
560					`INSERT INTO alert_rules (id, name, condition, severity, enabled, created_at, updated_at)
561					 VALUES ($1, '__sla_breach_system', $2, 'critical', true, NOW(), NOW())`,
562					slaRuleID, cond,
563				)
564				if err != nil {
565					return fmt.Errorf("alerts: create sla rule: %w", err)
566				}
567			} else if err != nil {
568				return fmt.Errorf("alerts: query sla rule: %w", err)
569			}
570	
571			data, _ := json.Marshal(map[string]interface{}{
572				"work_order_id": woID,
573				"reason":        "sla_breach",
574			})
575			_, _ = s.db.ExecContext(ctx,
576				`INSERT INTO alerts (id, rule_id, severity, status, data, created_at)
577				 VALUES ($1, $2, 'critical', 'new', $3, NOW())`,
578				uuid.New().String(), slaRuleID, data,
579			)
580		}
581	
582		return rows.Err()
583	}
