585	// inQuietHours checks if the given time falls within quiet hours.
586	func inQuietHours(startStr, endStr *string, now time.Time) bool {
587		if startStr == nil || endStr == nil || *startStr == "" || *endStr == "" {
588			return false
589		}
590	
591		start, err := time.Parse("15:04:05", *startStr)
592		if err != nil {
593			// Try without seconds
594			start, err = time.Parse("15:04", *startStr)
595			if err != nil {
596				return false
597			}
598		}
599		end, err := time.Parse("15:04:05", *endStr)
600		if err != nil {
601			end, err = time.Parse("15:04", *endStr)
602			if err != nil {
603				return false
604			}
605		}
606	
607		nowMinutes := now.Hour()*60 + now.Minute()
608		startMinutes := start.Hour()*60 + start.Minute()
609		endMinutes := end.Hour()*60 + end.Minute()
610	
611		if startMinutes <= endMinutes {
612			// Same day range: e.g., 08:00 - 17:00
613			return nowMinutes >= startMinutes && nowMinutes < endMinutes
614		}
615		// Overnight range: e.g., 22:00 - 07:00
616		return nowMinutes >= startMinutes || nowMinutes < endMinutes
617	}
