151	func TestSessionCleanupReal(t *testing.T) {
152		db := getTestDB(t)
153		_, _ = db.Exec("DELETE FROM auth_sessions")
154	
155		// Insert an expired session
156		_, err := db.Exec(
157			`INSERT INTO auth_sessions (user_id, token_hash, expires_at, last_active_at)
158			 VALUES ((SELECT id FROM users WHERE username='customer'), 'expired-hash-test', NOW() - INTERVAL '1 day', NOW() - INTERVAL '1 day')`)
159		if err != nil {
160			t.Fatalf("insert expired session: %v", err)
161		}
162	
163		var count int
164		db.QueryRow(`SELECT COUNT(*) FROM auth_sessions WHERE token_hash = 'expired-hash-test'`).Scan(&count)
165		if count != 1 {
166			t.Fatalf("expected 1 expired session before cleanup, got %d", count)
167		}
168	
169		// Use the real cleanup function
170		n, err := cleanup.ExpiredSessions(db)
171		if err != nil {
172			t.Fatalf("cleanup.ExpiredSessions: %v", err)
173		}
174		if n < 1 {
175			t.Fatalf("expected at least 1 session removed, got %d", n)
176		}
177	
178		db.QueryRow(`SELECT COUNT(*) FROM auth_sessions WHERE token_hash = 'expired-hash-test'`).Scan(&count)
179		if count != 0 {
180			t.Fatalf("expected 0 expired sessions after cleanup, got %d", count)
181		}
182	
183		// Idempotent: running again removes nothing
184		n2, _ := cleanup.ExpiredSessions(db)
185		if n2 != 0 {
186			t.Fatalf("idempotent rerun should remove 0, got %d", n2)
187		}
188	}
