266	// --- Audit file rotation and sealing ---
267	
268	func TestAuditFileRotationAndSealing(t *testing.T) {
269		tmpDir := t.TempDir()
270		sink := audit.NewFileSink(tmpDir)
271		defer sink.Close()
272	
273		yesterday := time.Date(2025, 6, 14, 23, 0, 0, 0, time.UTC)
274		sink.NowFn = func() time.Time { return yesterday }
275	
276		err := sink.Write(map[string]interface{}{
277			"event_type": "test_event",
278			"timestamp":  yesterday.Format(time.RFC3339),
279		})
280		if err != nil {
281			t.Fatalf("write yesterday event: %v", err)
282		}
283	
284		yesterdayFile := filepath.Join(tmpDir, "audit-2025-06-14.jsonl")
285		if _, err := os.Stat(yesterdayFile); os.IsNotExist(err) {
286			t.Fatal("yesterday audit file should exist")
287		}
288	
289		today := time.Date(2025, 6, 15, 8, 0, 0, 0, time.UTC)
290		sink.NowFn = func() time.Time { return today }
291	
292		err = sink.Write(map[string]interface{}{
293			"event_type": "today_event",
294			"timestamp":  today.Format(time.RFC3339),
295		})
296		if err != nil {
297			t.Fatalf("write today event: %v", err)
298		}
299	
300		todayFile := filepath.Join(tmpDir, "audit-2025-06-15.jsonl")
301		if _, err := os.Stat(todayFile); os.IsNotExist(err) {
302			t.Fatal("today audit file should exist")
303		}
304	
305		// Yesterday sealed as read-only
306		info, _ := os.Stat(yesterdayFile)
307		if info.Mode().Perm()&0222 != 0 {
308			t.Fatalf("yesterday file should be read-only, got %o", info.Mode().Perm())
309		}
310	
311		// Today still writable
312		info2, _ := os.Stat(todayFile)
313		if info2.Mode().Perm()&0200 == 0 {
314			t.Fatalf("today file should be writable, got %o", info2.Mode().Perm())
315		}
316	
317		data1, _ := os.ReadFile(yesterdayFile)
318		if !strings.Contains(string(data1), "test_event") {
319			t.Fatal("yesterday file should contain test_event")
320		}
321		data2, _ := os.ReadFile(todayFile)
322		if !strings.Contains(string(data2), "today_event") {
323			t.Fatal("today file should contain today_event")
324		}
325	}
