1	const API_BASE = "/api/v1";
2	
3	export interface ApiErrorBody {
4	  error: {
5	    code: string;
6	    message: string;
7	    field_errors?: Record<string, string[]>;
8	    request_id?: string;
9	  };
10	}
11	
12	export class ApiError extends Error {
13	  code: string;
14	  status: number;
15	  fieldErrors: Record<string, string[]>;
16	  requestId?: string;
17	
18	  constructor(status: number, body: ApiErrorBody) {
19	    super(body.error.message);
20	    this.name = "ApiError";
21	    this.status = status;
22	    this.code = body.error.code;
23	    this.fieldErrors = body.error.field_errors ?? {};
24	    this.requestId = body.error.request_id;
25	  }
26	}
27	
28	async function request<T>(
29	  path: string,
30	  options: RequestInit = {},
31	): Promise<T> {
32	  const res = await fetch(`${API_BASE}${path}`, {
33	    credentials: "include",
34	    headers: {
35	      "Content-Type": "application/json",
36	      ...options.headers,
37	    },
38	    ...options,
39	  });
40	
41	  if (!res.ok) {
42	    let body: ApiErrorBody;
43	    try {
44	      body = await res.json();
45	    } catch {
46	      throw new ApiError(res.status, {
47	        error: {
48	          code: "UNKNOWN",
49	          message: res.statusText,
50	        },
51	      });
52	    }
53	    throw new ApiError(res.status, body);
54	  }
55	
56	  if (res.status === 204) {
57	    return undefined as T;
58	  }
59	
60	  return res.json();
61	}
62	
63	export const api = {
64	  get: <T>(path: string) => request<T>(path),
65	
66	  post: <T>(path: string, body?: unknown) =>
67	    request<T>(path, {
68	      method: "POST",
69	      body: body ? JSON.stringify(body) : undefined,
70	    }),
71	
72	  put: <T>(path: string, body?: unknown) =>
73	    request<T>(path, {
74	      method: "PUT",
75	      body: body ? JSON.stringify(body) : undefined,
76	    }),
77	
78	  patch: <T>(path: string, body?: unknown) =>
79	    request<T>(path, {
80	      method: "PATCH",
81	      body: body ? JSON.stringify(body) : undefined,
82	    }),
83	
84	  delete: <T>(path: string) =>
85	    request<T>(path, { method: "DELETE" }),
86	};
