10	func testKey(t *testing.T) []byte {
11		t.Helper()
12		key := make([]byte, 32)
13		if _, err := rand.Read(key); err != nil {
14			t.Fatalf("failed to generate test key: %v", err)
15		}
16		os.Setenv("ENCRYPTION_KEY", hex.EncodeToString(key))
17		return key
18	}
19	
20	func TestEncryptDecrypt(t *testing.T) {
21		key := testKey(t)
22		plaintext := "+1-555-867-5309"
23	
24		ct, err := Encrypt(key, plaintext)
25		if err != nil {
26			t.Fatalf("Encrypt failed: %v", err)
27		}
28	
29		got, err := Decrypt(key, ct)
30		if err != nil {
31			t.Fatalf("Decrypt failed: %v", err)
32		}
33	
34		if got != plaintext {
35			t.Fatalf("round-trip mismatch: got %q, want %q", got, plaintext)
36		}
37	}
38	
39	func TestDecryptWrongKey(t *testing.T) {
40		key := testKey(t)
41		plaintext := "sensitive-data"
42	
43		ct, err := Encrypt(key, plaintext)
44		if err != nil {
45			t.Fatalf("Encrypt failed: %v", err)
46		}
47	
48		wrongKey := make([]byte, 32)
49		if _, err := rand.Read(wrongKey); err != nil {
50			t.Fatalf("failed to generate wrong key: %v", err)
51		}
52	
53		_, err = Decrypt(wrongKey, ct)
54		if err == nil {
55			t.Fatal("expected Decrypt to fail with wrong key, but it succeeded")
56		}
57	}
58	
59	func TestEncryptProducesDifferentCiphertext(t *testing.T) {
60		key := testKey(t)
61		plaintext := "same-input"
62	
63		ct1, err := Encrypt(key, plaintext)
64		if err != nil {
65			t.Fatalf("first Encrypt failed: %v", err)
66		}
67	
68		ct2, err := Encrypt(key, plaintext)
69		if err != nil {
70			t.Fatalf("second Encrypt failed: %v", err)
71		}
72	
73		if ct1 == ct2 {
74			t.Fatal("two encryptions of the same plaintext produced identical ciphertext; nonce reuse detected")
75		}
76	
77		// Both should still decrypt to the same plaintext
78		p1, _ := Decrypt(key, ct1)
79		p2, _ := Decrypt(key, ct2)
80		if p1 != plaintext || p2 != plaintext {
81			t.Fatal("decrypted values do not match original plaintext")
82		}
83	}
