1	package alerts
2	
3	import (
4		"context"
5		"database/sql"
6		"encoding/json"
7		"fmt"
8		"net/http"
9		"time"
10	
11		"fieldserve/internal/audit"
12		"fieldserve/internal/auth"
13		"fieldserve/internal/platform/httpx"
14	
15		"github.com/google/uuid"
16		"github.com/labstack/echo/v4"
17	)
18	
19	// Valid severity values.
20	var validSeverities = map[string]bool{
21		"low":      true,
22		"medium":   true,
23		"high":     true,
24		"critical": true,
25	}
26	
27	// Supported metrics that the worker can evaluate.
28	var supportedMetrics = map[string]bool{
29		"unresolved_interests":      true,
30		"low_provider_utilization":  true,
31		"overdue_work_orders":       true,
32	}
33	
34	// Service manages alert rules, alerts, and assignments.
35	type Service struct {
36		db    *sql.DB
37		audit *audit.Service
38	}
39	
40	// NewService creates a new alerts service.
41	func NewService(db *sql.DB, audit *audit.Service) *Service {
42		return &Service{db: db, audit: audit}
43	}
44	
45	// AlertRule represents an alert rule configuration.
46	type AlertRule struct {
47		ID              string          `json:"id"`
48		Name            string          `json:"name"`
49		Condition       json.RawMessage `json:"condition"`
50		Severity        string          `json:"severity"`
51		QuietHoursStart *string         `json:"quiet_hours_start"`
52		QuietHoursEnd   *string         `json:"quiet_hours_end"`
53		Enabled         bool            `json:"enabled"`
54		CreatedAt       string          `json:"created_at"`
55		UpdatedAt       string          `json:"updated_at"`
56	}
57	
58	// Alert represents a triggered alert.
59	type Alert struct {
60		ID         string          `json:"id"`
61		RuleID     string          `json:"rule_id"`
62		Severity   string          `json:"severity"`
63		Status     string          `json:"status"`
64		Data       json.RawMessage `json:"data"`
65		CreatedAt  string          `json:"created_at"`
66		ResolvedAt *string         `json:"resolved_at"`
67	}
68	
69	// AlertWithRule includes the rule name for list views.
70	type AlertWithRule struct {
71		Alert
72		RuleName string `json:"rule_name"`
73	}
74	
75	// Assignment represents an alert-to-user assignment.
76	type Assignment struct {
77		ID             string  `json:"id"`
78		AlertID        string  `json:"alert_id"`
79		AssigneeID     string  `json:"assignee_id"`
80		AssignedAt     string  `json:"assigned_at"`
81		AcknowledgedAt *string `json:"acknowledged_at"`
82	}
83	
84	// HandleListRules handles GET /admin/alert-rules.
85	func (s *Service) HandleListRules(c echo.Context) error {
86		rows, err := s.db.QueryContext(c.Request().Context(),
87			`SELECT id, name, condition, severity, quiet_hours_start::text, quiet_hours_end::text, enabled, created_at::text, updated_at::text
88			 FROM alert_rules ORDER BY created_at DESC`)
89		if err != nil {
90			return fmt.Errorf("alerts: list rules: %w", err)
91		}
92		defer rows.Close()
93	
94		rules := []AlertRule{}
95		for rows.Next() {
96			var r AlertRule
97			if err := rows.Scan(&r.ID, &r.Name, &r.Condition, &r.Severity, &r.QuietHoursStart, &r.QuietHoursEnd, &r.Enabled, &r.CreatedAt, &r.UpdatedAt); err != nil {
98				return fmt.Errorf("alerts: scan rule: %w", err)
99			}
100			rules = append(rules, r)
101		}
102		if err := rows.Err(); err != nil {
103			return fmt.Errorf("alerts: rules rows: %w", err)
104		}
105	
106		return c.JSON(http.StatusOK, map[string]interface{}{"alert_rules": rules})
107	}
108	
109	// HandleCreateRule handles POST /admin/alert-rules.
110	func (s *Service) HandleCreateRule(c echo.Context) error {
111		ctx := c.Request().Context()
112		user := auth.UserFromContext(c)
113	
114		var req struct {
115			Name            string          `json:"name"`
116			Condition       json.RawMessage `json:"condition"`
117			Severity        string          `json:"severity"`
118			QuietHoursStart *string         `json:"quiet_hours_start"`
119			QuietHoursEnd   *string         `json:"quiet_hours_end"`
120			Enabled         *bool           `json:"enabled"`
121		}
122		if err := c.Bind(&req); err != nil {
123			return httpx.NewAPIError(http.StatusBadRequest, "bad_request", "Invalid request body.")
124		}
125	
126		// Validate
127		fieldErrors := map[string][]string{}
128		if req.Name == "" {
129			fieldErrors["name"] = []string{"Name is required."}
130		}
131		if !validSeverities[req.Severity] {
132			fieldErrors["severity"] = []string{"Severity must be one of: low, medium, high, critical."}
133		}
134		if len(req.Condition) == 0 || string(req.Condition) == "null" {
135			fieldErrors["condition"] = []string{"Condition is required."}
136		} else {
137			var cond struct{ Metric string `json:"metric"` }
138			if json.Unmarshal(req.Condition, &cond) == nil && cond.Metric != "" && !supportedMetrics[cond.Metric] {
139				fieldErrors["condition"] = []string{"Unsupported metric. Supported: unresolved_interests, low_provider_utilization, overdue_work_orders."}
140			}
141		}
142		if len(fieldErrors) > 0 {
143			return httpx.NewValidationError(fieldErrors)
144		}
145	
146		enabled := true
147		if req.Enabled != nil {
148			enabled = *req.Enabled
149		}
150	
151		var r AlertRule
152		err := s.db.QueryRowContext(ctx,
153			`INSERT INTO alert_rules (id, name, condition, severity, quiet_hours_start, quiet_hours_end, enabled, created_at, updated_at)
154			 VALUES ($1, $2, $3, $4, $5, $6, $7, NOW(), NOW())
155			 RETURNING id, name, condition, severity, quiet_hours_start::text, quiet_hours_end::text, enabled, created_at::text, updated_at::text`,
156			uuid.New().String(), req.Name, req.Condition, req.Severity, req.QuietHoursStart, req.QuietHoursEnd, enabled,
157		).Scan(&r.ID, &r.Name, &r.Condition, &r.Severity, &r.QuietHoursStart, &r.QuietHoursEnd, &r.Enabled, &r.CreatedAt, &r.UpdatedAt)
158		if err != nil {
159			return fmt.Errorf("alerts: create rule: %w", err)
160		}
161	
162		s.audit.Log(ctx, audit.Event{
163			EventType:    "alert_rule_created",
164			ActorID:      user.ID,
165			ResourceType: "alert_rule",
166			ResourceID:   r.ID,
167			Metadata:     map[string]interface{}{"name": r.Name, "severity": r.Severity},
168		})
169	
170		return c.JSON(http.StatusCreated, map[string]interface{}{"alert_rule": r})
171	}
172	
173	// HandleUpdateRule handles PATCH /admin/alert-rules/:ruleId.
174	func (s *Service) HandleUpdateRule(c echo.Context) error {
175		ctx := c.Request().Context()
176		user := auth.UserFromContext(c)
177		ruleID := c.Param("ruleId")
178	
179		// Check rule exists
180		var existing AlertRule
181		err := s.db.QueryRowContext(ctx,
182			`SELECT id, name, condition, severity, quiet_hours_start::text, quiet_hours_end::text, enabled, created_at::text, updated_at::text
183			 FROM alert_rules WHERE id = $1`, ruleID,
184		).Scan(&existing.ID, &existing.Name, &existing.Condition, &existing.Severity, &existing.QuietHoursStart, &existing.QuietHoursEnd, &existing.Enabled, &existing.CreatedAt, &existing.UpdatedAt)
185		if err == sql.ErrNoRows {
186			return httpx.NewNotFoundError("Alert rule not found.")
187		}
188		if err != nil {
189			return fmt.Errorf("alerts: get rule: %w", err)
190		}
191	
192		var req struct {
193			Name            *string          `json:"name"`
194			Condition       *json.RawMessage `json:"condition"`
195			Severity        *string          `json:"severity"`
196			QuietHoursStart *string          `json:"quiet_hours_start"`
197			QuietHoursEnd   *string          `json:"quiet_hours_end"`
198			Enabled         *bool            `json:"enabled"`
199		}
200		if err := c.Bind(&req); err != nil {
201			return httpx.NewAPIError(http.StatusBadRequest, "bad_request", "Invalid request body.")
202		}
203	
204		// Apply partial updates
205		name := existing.Name
206		if req.Name != nil {
207			name = *req.Name
208		}
209		condition := existing.Condition
210		if req.Condition != nil {
211			condition = *req.Condition
212			// Validate metric
213			var cond struct{ Metric string `json:"metric"` }
214			if json.Unmarshal(condition, &cond) == nil && cond.Metric != "" && !supportedMetrics[cond.Metric] {
215				return httpx.NewValidationError(map[string][]string{
216					"condition": {"Unsupported metric. Supported: unresolved_interests, low_provider_utilization, overdue_work_orders."},
217				})
218			}
219		}
220		severity := existing.Severity
221		if req.Severity != nil {
222			if !validSeverities[*req.Severity] {
223				return httpx.NewValidationError(map[string][]string{
224					"severity": {"Severity must be one of: low, medium, high, critical."},
225				})
226			}
227			severity = *req.Severity
228		}
229		enabled := existing.Enabled
230		if req.Enabled != nil {
231			enabled = *req.Enabled
232		}
233		quietStart := existing.QuietHoursStart
234		if req.QuietHoursStart != nil {
235			quietStart = req.QuietHoursStart
236		}
237		quietEnd := existing.QuietHoursEnd
238		if req.QuietHoursEnd != nil {
239			quietEnd = req.QuietHoursEnd
240		}
241	
242		var r AlertRule
243		err = s.db.QueryRowContext(ctx,
244			`UPDATE alert_rules SET name = $1, condition = $2, severity = $3, quiet_hours_start = $4, quiet_hours_end = $5, enabled = $6, updated_at = NOW()
245			 WHERE id = $7
246			 RETURNING id, name, condition, severity, quiet_hours_start::text, quiet_hours_end::text, enabled, created_at::text, updated_at::text`,
247			name, condition, severity, quietStart, quietEnd, enabled, ruleID,
248		).Scan(&r.ID, &r.Name, &r.Condition, &r.Severity, &r.QuietHoursStart, &r.QuietHoursEnd, &r.Enabled, &r.CreatedAt, &r.UpdatedAt)
249		if err != nil {
250			return fmt.Errorf("alerts: update rule: %w", err)
251		}
252	
253		s.audit.Log(ctx, audit.Event{
254			EventType:    "alert_rule_updated",
255			ActorID:      user.ID,
256			ResourceType: "alert_rule",
257			ResourceID:   r.ID,
258			Metadata:     map[string]interface{}{"name": r.Name},
259		})
260	
261		return c.JSON(http.StatusOK, map[string]interface{}{"alert_rule": r})
262	}
263	
264	// HandleListAlerts handles GET /admin/alerts.
265	func (s *Service) HandleListAlerts(c echo.Context) error {
266		rows, err := s.db.QueryContext(c.Request().Context(),
267			`SELECT a.id, a.rule_id, a.severity, a.status, a.data, a.created_at::text, a.resolved_at::text, ar.name
268			 FROM alerts a
269			 JOIN alert_rules ar ON ar.id = a.rule_id
270			 ORDER BY a.created_at DESC`)
271		if err != nil {
272			return fmt.Errorf("alerts: list alerts: %w", err)
273		}
274		defer rows.Close()
275	
276		alerts := []AlertWithRule{}
277		for rows.Next() {
278			var a AlertWithRule
279			if err := rows.Scan(&a.ID, &a.RuleID, &a.Severity, &a.Status, &a.Data, &a.CreatedAt, &a.ResolvedAt, &a.RuleName); err != nil {
280				return fmt.Errorf("alerts: scan alert: %w", err)
281			}
282			alerts = append(alerts, a)
283		}
284		if err := rows.Err(); err != nil {
285			return fmt.Errorf("alerts: alerts rows: %w", err)
286		}
287	
288		return c.JSON(http.StatusOK, map[string]interface{}{"alerts": alerts})
289	}
290	
291	// HandleGetAlert handles GET /admin/alerts/:alertId.
292	func (s *Service) HandleGetAlert(c echo.Context) error {
293		ctx := c.Request().Context()
294		alertID := c.Param("alertId")
295	
296		var a AlertWithRule
297		err := s.db.QueryRowContext(ctx,
298			`SELECT a.id, a.rule_id, a.severity, a.status, a.data, a.created_at::text, a.resolved_at::text, ar.name
299			 FROM alerts a
300			 JOIN alert_rules ar ON ar.id = a.rule_id
301			 WHERE a.id = $1`, alertID,
302		).Scan(&a.ID, &a.RuleID, &a.Severity, &a.Status, &a.Data, &a.CreatedAt, &a.ResolvedAt, &a.RuleName)
303		if err == sql.ErrNoRows {
304			return httpx.NewNotFoundError("Alert not found.")
305		}
306		if err != nil {
307			return fmt.Errorf("alerts: get alert: %w", err)
308		}
309	
310		// Fetch assignments
311		assignRows, err := s.db.QueryContext(ctx,
312			`SELECT id, alert_id, assignee_id, assigned_at::text, acknowledged_at::text
313			 FROM alert_assignments WHERE alert_id = $1`, alertID)
314		if err != nil {
315			return fmt.Errorf("alerts: list assignments: %w", err)
316		}
317		defer assignRows.Close()
318	
319		assignments := []Assignment{}
320		for assignRows.Next() {
321			var asgn Assignment
322			if err := assignRows.Scan(&asgn.ID, &asgn.AlertID, &asgn.AssigneeID, &asgn.AssignedAt, &asgn.AcknowledgedAt); err != nil {
323				return fmt.Errorf("alerts: scan assignment: %w", err)
324			}
325			assignments = append(assignments, asgn)
326		}
327		if err := assignRows.Err(); err != nil {
328			return fmt.Errorf("alerts: assignment rows: %w", err)
329		}
330	
331		return c.JSON(http.StatusOK, map[string]interface{}{
332			"alert":       a,
333			"assignments": assignments,
334		})
335	}
336	
337	// OnCallSchedule represents an on-call schedule entry.
338	type OnCallSchedule struct {
339		ID        string `json:"id"`
340		UserID    string `json:"user_id"`
341		Tier      int    `json:"tier"`
342		StartTime string `json:"start_time"`
343		EndTime   string `json:"end_time"`
344		CreatedAt string `json:"created_at"`
345	}
346	
347	// HandleListOnCall handles GET /admin/on-call — lists all on-call schedules.
348	func (s *Service) HandleListOnCall(c echo.Context) error {
349		rows, err := s.db.QueryContext(c.Request().Context(),
350			`SELECT id, user_id, tier, start_time::text, end_time::text, created_at::text
351			 FROM on_call_schedules ORDER BY tier, start_time`)
352		if err != nil {
353			return fmt.Errorf("alerts: list on-call: %w", err)
354		}
355		defer rows.Close()
356	
357		schedules := []OnCallSchedule{}
358		for rows.Next() {
359			var s OnCallSchedule
360			if err := rows.Scan(&s.ID, &s.UserID, &s.Tier, &s.StartTime, &s.EndTime, &s.CreatedAt); err != nil {
361				return fmt.Errorf("alerts: scan on-call: %w", err)
362			}
363			schedules = append(schedules, s)
364		}
365		return c.JSON(http.StatusOK, map[string]interface{}{"on_call_schedules": schedules})
366	}
367	
368	// HandleCreateOnCall handles POST /admin/on-call — creates an on-call schedule.
369	func (s *Service) HandleCreateOnCall(c echo.Context) error {
370		ctx := c.Request().Context()
371		user := auth.UserFromContext(c)
372	
373		var req struct {
374			UserID    string `json:"user_id"`
375			Tier      int    `json:"tier"`
376			StartTime string `json:"start_time"`
377			EndTime   string `json:"end_time"`
378		}
379		if err := c.Bind(&req); err != nil {
380			return httpx.NewAPIError(http.StatusBadRequest, "bad_request", "Invalid request body.")
381		}
382	
383		fieldErrors := map[string][]string{}
384		if req.UserID == "" {
385			fieldErrors["user_id"] = []string{"User ID is required."}
386		}
387		if req.Tier < 1 || req.Tier > 3 {
388			fieldErrors["tier"] = []string{"Tier must be 1, 2, or 3."}
389		}
390		if req.StartTime == "" {
391			fieldErrors["start_time"] = []string{"Start time is required."}
392		}
393		if req.EndTime == "" {
394			fieldErrors["end_time"] = []string{"End time is required."}
395		}
396		if len(fieldErrors) > 0 {
397			return httpx.NewValidationError(fieldErrors)
398		}
399	
400		// Verify user exists and has administrator role
401		var userExists bool
402		s.db.QueryRowContext(ctx,
403			`SELECT EXISTS(SELECT 1 FROM user_roles ur JOIN roles r ON r.id = ur.role_id WHERE ur.user_id = $1 AND r.name = 'administrator')`,
404			req.UserID,
405		).Scan(&userExists)
406		if !userExists {
407			return httpx.NewValidationError(map[string][]string{
408				"user_id": {"User must have administrator role to be on-call."},
409			})
410		}
411	
