448	func (s *Service) HandleAssignAlert(c echo.Context) error {
449		ctx := c.Request().Context()
450		user := auth.UserFromContext(c)
451		alertID := c.Param("alertId")
452	
453		// Check alert exists
454		var exists bool
455		err := s.db.QueryRowContext(ctx, `SELECT EXISTS(SELECT 1 FROM alerts WHERE id = $1)`, alertID).Scan(&exists)
456		if err != nil {
457			return fmt.Errorf("alerts: check alert: %w", err)
458		}
459		if !exists {
460			return httpx.NewNotFoundError("Alert not found.")
461		}
462	
463		var req struct {
464			AssigneeID string `json:"assignee_id"`
465		}
466		if err := c.Bind(&req); err != nil {
467			return httpx.NewAPIError(http.StatusBadRequest, "bad_request", "Invalid request body.")
468		}
469		if req.AssigneeID == "" {
470			return httpx.NewValidationError(map[string][]string{
471				"assignee_id": {"Assignee ID is required."},
472			})
473		}
474	
475		// Enforce on-call eligibility
476		onCall, err := s.isUserOnCall(ctx, req.AssigneeID)
477		if err != nil {
478			return fmt.Errorf("alerts: check on-call: %w", err)
479		}
