538	// EvaluateRules checks all enabled alert rules and creates alerts as needed.
539	func (s *Service) EvaluateRules(ctx context.Context, now time.Time) error {
540		rows, err := s.db.QueryContext(ctx,
541			`SELECT id, name, condition, severity, quiet_hours_start::text, quiet_hours_end::text, enabled
542			 FROM alert_rules WHERE enabled = true`)
543		if err != nil {
544			return fmt.Errorf("alerts: query rules: %w", err)
545		}
546		defer rows.Close()
547	
548		type ruleRow struct {
549			id              string
550			name            string
551			condition       json.RawMessage
552			severity        string
553			quietHoursStart *string
554			quietHoursEnd   *string
555		}
556	
557		var rules []ruleRow
558		for rows.Next() {
559			var r ruleRow
560			var enabled bool
561			if err := rows.Scan(&r.id, &r.name, &r.condition, &r.severity, &r.quietHoursStart, &r.quietHoursEnd, &enabled); err != nil {
562				return fmt.Errorf("alerts: scan rule: %w", err)
563			}
564			rules = append(rules, r)
565		}
566		if err := rows.Err(); err != nil {
567			return fmt.Errorf("alerts: rules rows: %w", err)
568		}
569	
570		for _, rule := range rules {
571			// Check quiet hours
572			if rule.severity != "critical" && inQuietHours(rule.quietHoursStart, rule.quietHoursEnd, now) {
573				continue
574			}
575	
576			// Parse condition
577			var cond struct {
578				Metric    string `json:"metric"`
579				Threshold int    `json:"threshold"`
580			}
581			if err := json.Unmarshal(rule.condition, &cond); err != nil {
582				continue
583			}
584	
585			// Evaluate metric
586			var metricValue int
587			var evalErr error
588			switch cond.Metric {
589			case "unresolved_interests":
590				evalErr = s.db.QueryRowContext(ctx,
591					`SELECT COUNT(*) FROM interests WHERE status = 'submitted' AND created_at < NOW() - INTERVAL '3 days'`,
592				).Scan(&metricValue)
593			case "low_provider_utilization":
594				evalErr = s.db.QueryRowContext(ctx,
595					`SELECT COUNT(*) FROM provider_profiles pp
596					 WHERE NOT EXISTS (SELECT 1 FROM services s WHERE s.provider_id = pp.id AND s.status = 'active')`,
597				).Scan(&metricValue)
598			case "overdue_work_orders":
599				evalErr = s.db.QueryRowContext(ctx,
600					`SELECT COUNT(*) FROM work_orders
601					 WHERE status IN ('dispatched', 'acknowledged', 'in_progress')
602					 AND updated_at < NOW() - INTERVAL '24 hours'`,
603				).Scan(&metricValue)
604			default:
605				continue
606			}
607			if evalErr != nil {
608				continue
609			}
610	
611			if metricValue < cond.Threshold {
612				continue
613			}
614	
615			// Check for recent unresolved alert for this rule (last hour)
616			var recentCount int
617			s.db.QueryRowContext(ctx,
618				`SELECT COUNT(*) FROM alerts
619				 WHERE rule_id = $1 AND status != 'resolved' AND created_at > NOW() - INTERVAL '1 hour'`,
620				rule.id,
621			).Scan(&recentCount)
622			if recentCount > 0 {
623				continue
624			}
625	
626			// Create alert
627			data, _ := json.Marshal(map[string]interface{}{
628				"metric": cond.Metric,
629				"value":  metricValue,
630			})
631			_, err := s.db.ExecContext(ctx,
632				`INSERT INTO alerts (id, rule_id, severity, status, data, created_at)
633				 VALUES ($1, $2, $3, 'new', $4, NOW())`,
634				uuid.New().String(), rule.id, rule.severity, data,
635			)
636			if err != nil {
637				continue
638			}
639		}
640	
641		return nil
642	}
643	
644	// CheckSLADeadlines finds overdue work orders and creates critical alerts.
645	func (s *Service) CheckSLADeadlines(ctx context.Context, now time.Time) error {
646		rows, err := s.db.QueryContext(ctx,
647			`SELECT id FROM work_orders
648			 WHERE status IN ('dispatched', 'acknowledged', 'in_progress')
649			 AND updated_at < NOW() - INTERVAL '24 hours'`)
650		if err != nil {
651			return fmt.Errorf("alerts: sla check query: %w", err)
652		}
653		defer rows.Close()
654	
655		for rows.Next() {
656			var woID string
657			if err := rows.Scan(&woID); err != nil {
658				continue
659			}
660	
661			// Check for existing SLA alert for this work order in last hour
662			var recentCount int
663			s.db.QueryRowContext(ctx,
664				`SELECT COUNT(*) FROM alerts
665				 WHERE status != 'resolved' AND data->>'work_order_id' = $1 AND created_at > NOW() - INTERVAL '1 hour'`,
666				woID,
667			).Scan(&recentCount)
668			if recentCount > 0 {
669				continue
670			}
671	
672			// We need a rule_id for SLA alerts. Use a sentinel approach: find or create a system SLA rule.
673			var slaRuleID string
674			err := s.db.QueryRowContext(ctx,
675				`SELECT id FROM alert_rules WHERE name = '__sla_breach_system'`,
676			).Scan(&slaRuleID)
677			if err == sql.ErrNoRows {
678				slaRuleID = uuid.New().String()
679				cond, _ := json.Marshal(map[string]string{"metric": "sla_breach"})
680				_, err = s.db.ExecContext(ctx,
681					`INSERT INTO alert_rules (id, name, condition, severity, enabled, created_at, updated_at)
682					 VALUES ($1, '__sla_breach_system', $2, 'critical', true, NOW(), NOW())`,
683					slaRuleID, cond,
684				)
685				if err != nil {
686					return fmt.Errorf("alerts: create sla rule: %w", err)
687				}
688			} else if err != nil {
689				return fmt.Errorf("alerts: query sla rule: %w", err)
690			}
691	
692			data, _ := json.Marshal(map[string]interface{}{
693				"work_order_id": woID,
694				"reason":        "sla_breach",
695			})
696			_, _ = s.db.ExecContext(ctx,
697				`INSERT INTO alerts (id, rule_id, severity, status, data, created_at)
698				 VALUES ($1, $2, 'critical', 'new', $3, NOW())`,
699				uuid.New().String(), slaRuleID, data,
700			)
701		}
702	
703		return rows.Err()
704	}
