706	// inQuietHours checks if the given time falls within quiet hours.
707	func inQuietHours(startStr, endStr *string, now time.Time) bool {
708		if startStr == nil || endStr == nil || *startStr == "" || *endStr == "" {
709			return false
710		}
711	
712		start, err := time.Parse("15:04:05", *startStr)
713		if err != nil {
714			// Try without seconds
715			start, err = time.Parse("15:04", *startStr)
716			if err != nil {
717				return false
718			}
719		}
720		end, err := time.Parse("15:04:05", *endStr)
721		if err != nil {
722			end, err = time.Parse("15:04", *endStr)
723			if err != nil {
724				return false
725			}
726		}
727	
728		nowMinutes := now.Hour()*60 + now.Minute()
729		startMinutes := start.Hour()*60 + start.Minute()
730		endMinutes := end.Hour()*60 + end.Minute()
731	
732		if startMinutes <= endMinutes {
733			// Same day range: e.g., 08:00 - 17:00
734			return nowMinutes >= startMinutes && nowMinutes < endMinutes
735		}
736		// Overnight range: e.g., 22:00 - 07:00
737		return nowMinutes >= startMinutes || nowMinutes < endMinutes
738	}
